#!/usr/bin/env node
/**
 * ROS BMS Permanent Patch Script v2
 * Run from project root: node patch.js
 * Applies all permanent fixes to src/App.jsx and src/SalesPanel.jsx
 * Safe to run multiple times — skips already-applied patches
 */
const fs=require('fs'),path=require('path');
const APP=path.join(__dirname,'src','App.jsx');
const SP=path.join(__dirname,'src','SalesPanel.jsx');
if(!fs.existsSync(APP)){console.error('src/App.jsx not found');process.exit(1);}
if(!fs.existsSync(SP)){console.error('src/SalesPanel.jsx not found');process.exit(1);}
let src=fs.readFileSync(APP);
let sp=fs.readFileSync(SP);
const done=[],skipped=[];
function b(hex){return Buffer.from(hex,'hex');}
function ap(label,o,n,t='app'){
  const s=t==='app'?src:sp;
  if(s.includes(n)){skipped.push(label);return;}
  if(!s.includes(o)){console.error('NOT FOUND: '+label);process.exit(1);}
  const i=s.indexOf(o);
  const r=Buffer.concat([s.slice(0,i),n,s.slice(i+o.length)]);
  if(t==='app')src=r; else sp=r;
  done.push(label);
}

